"""Fixtures extracted from the n8n workflow JSON exports (ops/n8n/workflows/).

These are the exact payload shapes the three workflows validated and produced.
They feed the equivalence tests of the ported bridges (wr_bridge.py) and
replace workflow #3 (IMPERIUM_WR_INTERACTIVE_START_MOCK), whose only value was
contract testing — the JSON export is deleted from the repo (N8N_INVENTORY §A).
"""


def interactive_start_payload(*, task_id: str, session_id: str) -> dict:
    """Webhook input of IMPERIUM_WR_INTERACTIVE_START_QWEN_DRY_RUN."""
    return {
        "task_id": task_id,
        "session_id": session_id,
        "task_type": "weekly_report.interactive.start",
        "week_start": "2026-07-06",
        "week_end": "2026-07-12",
        "callback_url": f"/api/internal/ai/tasks/{task_id}/result",
        "wr_attach_url": f"/api/internal/weekly-review/{session_id}/attach-ai-result",
    }


def answers_integrate_payload(
    *, task_id: str, session_id: str, user_message_id: str, user_answer: str
) -> dict:
    """Webhook input of IMPERIUM_WR_ANSWERS_INTEGRATE_QWEN_DRY_RUN."""
    return {
        **interactive_start_payload(task_id=task_id, session_id=session_id),
        "task_type": "weekly_report.answers.integrate",
        "user_message_id": user_message_id,
        "user_answer": user_answer,
    }


