EXPECTED_START_IDEMPOTENCY_TEMPLATE = "wr_qwen_dry_run_result_{task_id}"
EXPECTED_START_ATTACH_TEMPLATE = "wr_qwen_dry_run_attach_{session_id}_{result_id}"

# Expected callback body of workflow #2 (Validate Payload and Sign Result Callback).
EXPECTED_ANSWERS_CALLBACK_RESULT_TYPE = "weekly_report.draft"
